export interface TestFixtures {
  testUser: TestUser;
  testBusiness: TestBusiness;
  testProduct: TestProduct;
  testReview: TestReview;
}

export const test = base.extend<TestFixtures>({
  // This allows tests to access the factories
  testUser: async ({ page }, use) => {
    await use(UserFactory.build());
  },
  testBusiness: async ({ page }, use) => {
    const user = UserFactory.build();
    await use(BusinessFactory.build(user.id));
  },
  testProduct: async ({ page }, use) => {
    const user = UserFactory.build();
    const business = BusinessFactory.build(user.id);
    await use(ProductFactory.build(business.id));
  },
  testReview: async ({ page }, use) => {
    const user = UserFactory.build();
    const business = BusinessFactory.build(user.id);
    await use(ReviewFactory.build(business.id, user.id));
  },
});

// ============================================
// Helper Functions
// ============================================

/**
 * Clean up test data after tests
 */
export async function cleanupTestData(page: Page) {
  // Clear cookies - safely ignore localStorage errors
  await page.context().clearCookies();
  try {
    // Only clear localStorage if the page allows it (not about:blank or cross-origin)
    const url = page.url();
    if (url && !url.startsWith('about:') && url.startsWith('http')) {
      await page.evaluate(() => localStorage.clear());
    }
  } catch {
    // Ignore localStorage errors - page might be restricted
  }
}

/**
 * Login as test user
 */
export async function loginAsUser(page: Page, email?: string, password?: string) {
  await page.goto('/login');
  await page.fill('input[name="email"]', email || 'test@example.com');
  await page.fill('input[name="password"]', password || 'TestPassword123!');
  await page.click('button[type="submit"]');
  await page.waitForURL('/dashboard');
}

/**
 * Login as admin
 */
export async function loginAsAdmin(page: Page) {
  await page.goto('/admin/login');
  await page.fill('input[name="email"]', 'admin@example.com');
  await page.fill('input[name="password"]', 'admin123');
  await page.click('button[type="submit"]');
  
  // Wait for navigation to complete (the page will redirect to /admin on success)
  try {
    await page.waitForURL('**/admin**', { timeout: 5000 });
  } catch (e) {
    // If redirect doesn't happen, check if there's an error message
    const errorMsg = await page.locator('#error-message').textContent();
    if (errorMsg && !errorMsg.includes('hidden')) {
      throw new Error(`Login failed: ${errorMsg}`);
    }
  }
  
  // Wait a bit for cookies to be set
  await page.waitForTimeout(500);
}

